// n8n Code Node - Transform Clockify Time Entries to Database Format

const timeEntries = $input.first().json.timeentries;

const transformedEntries = timeEntries.map(entry => {
  return {
    json: {
      id: entry._id,
      description: entry.description || null,
      userId: entry.userId,
      userName: entry.userName || null,
      userEmail: entry.userEmail || null,
      projectId: entry.projectId,
      projectName: entry.projectName || null,
      projectColor: entry.projectColor || null,
      clientId: entry.clientId || null,
      clientName: entry.clientName || null,
      taskId: entry.taskId,
      approvalRequestId: entry.approvalRequestId,

      // Time Interval
      time_start: entry.timeInterval?.start || null,
      time_end: entry.timeInterval?.end || null,
      time_duration: entry.timeInterval?.duration || null,
      time_timezone: entry.timeInterval?.timeZone || null,
      time_zoned_start: entry.timeInterval?.zonedStart || null,
      time_zoned_end: entry.timeInterval?.zonedEnd || null,
      time_off_start: entry.timeInterval?.offStart || null,
      time_off_end: entry.timeInterval?.offEnd || null,

      billable: entry.billable,
      type: entry.type,
      isLocked: entry.isLocked,
      currency: entry.currency,

      // Financial Values
      amount: entry.amount,
      rate: entry.rate,
      earnedAmount: entry.earnedAmount,
      earnedRate: entry.earnedRate,
      costAmount: entry.costAmount,
      costRate: entry.costRate
    }
  };
});

return transformedEntries;

// Clockify extraction and normalization

const pairedItem = $input.first().pairedItem ?? { item: 0 };

function withPair(items) {
  return items.map(item => ({ ...item, pairedItem }));
}

function asList(value) {
  if (Array.isArray(value)) return value;
  if (value && typeof value === 'object') {
    if (Array.isArray(value.data)) return value.data;
    if (Array.isArray(value.value)) return value.value;
    return [value];
  }
  return [];
}

function collectRecords() {
  const items = $input.all();
  let records = [];
  for (const item of items) {
    records = records.concat(asList(item.json));
  }
  return records;
}

function transformUsers(users) {
  return withPair(users.map(user => {
    const settings = user.settings || {};
    return {
      json: {
        id: String(user.id || ''),
        email: user.email,
        name: user.name,
        profilePicture: user.profilePicture,
        activeWorkspace: user.activeWorkspace,
        defaultWorkspace: user.defaultWorkspace,
        status: user.status,
        weekStart: settings.weekStart,
        timeZone: settings.timeZone,
        timeFormat: settings.timeFormat,
        dateFormat: settings.dateFormat,
        sendNewsletter: settings.sendNewsletter,
        weeklyUpdates: settings.weeklyUpdates,
        longRunning: settings.longRunning,
        scheduledReports: settings.scheduledReports,
        approval: settings.approval,
        pto: settings.pto,
        alerts: settings.alerts,
        reminders: settings.reminders,
        timeTrackingManual: settings.timeTrackingManual,
        isCompactViewOn: settings.isCompactViewOn,
        dashboardSelection: settings.dashboardSelection,
        dashboardViewType: settings.dashboardViewType,
        dashboardPinToTop: settings.dashboardPinToTop,
        projectListCollapse: settings.projectListCollapse,
        collapseAllProjectLists: settings.collapseAllProjectLists,
        groupSimilarEntriesDisabled: settings.groupSimilarEntriesDisabled,
        myStartOfDay: settings.myStartOfDay,
        projectPickerTaskFilter: settings.projectPickerTaskFilter,
        lang: settings.lang,
        multiFactorEnabled: settings.multiFactorEnabled,
        theme: settings.theme,
        scheduling: settings.scheduling,
        onboarding: settings.onboarding,
        invoiceReminders: settings.invoiceReminders,
        showOnlyWorkingDays: settings.showOnlyWorkingDays,
        memberships: user.memberships,
        summaryReportSettings: settings.summaryReportSettings,
        customFields: user.customFields
      }
    };
  }));
}

function transformProjects(projects) {
  return withPair(projects.map(project => {
    const hourlyRate = project.hourlyRate || {};
    const costRate = project.costRate || {};
    const estimate = project.estimate || {};
    const timeEstimate = project.timeEstimate || {};
    const budgetEstimate = project.budgetEstimate || {};
    return {
      json: {
        id: String(project.id || ''),
        name: project.name,
        clientId: project.clientId,
        workspaceId: project.workspaceId,
        billable: project.billable,
        archived: project.archived,
        color: project.color,
        duration: project.duration,
        clientName: project.clientName,
        note: project.note,
        public: project.public,
        template: project.template,
        hourly_amount: hourlyRate.amount,
        hourly_currency: hourlyRate.currency,
        cost_amount: costRate.amount,
        cost_currency: costRate.currency,
        estimate_value: estimate.estimate,
        estimate_type: estimate.type,
        time_est_estimate: timeEstimate.estimate,
        time_est_type: timeEstimate.type,
        time_est_reset_option: timeEstimate.resetOption,
        time_est_active: timeEstimate.active,
        time_est_include_non_billable: timeEstimate.includeNonBillable,
        budget_est_estimate: budgetEstimate.estimate,
        budget_est_type: budgetEstimate.type,
        budget_est_reset_option: budgetEstimate.resetOption,
        budget_est_active: budgetEstimate.active,
        memberships: project.memberships
      }
    };
  }));
}

function transformClients(clients) {
  return withPair(clients.map(client => ({
    json: {
      id: String(client.id || ''),
      name: client.name,
      email: client.email,
      ccEmails: client.ccEmails,
      workspaceId: client.workspaceId,
      archived: client.archived,
      address: client.address,
      note: client.note,
      currencyId: client.currencyId,
      currencyCode: client.currencyCode
    }
  })));
}

function transformTags(tags) {
  return withPair(tags.map(tag => ({
    json: {
      id: String(tag.id || ''),
      name: tag.name,
      workspaceId: tag.workspaceId,
      archived: tag.archived
    }
  })));
}

function detectKind(sample) {
  if (!sample || typeof sample !== 'object') return 'generic';
  if ('settings' in sample) return 'users';
  if ('hourlyRate' in sample || 'estimate' in sample || 'timeEstimate' in sample || 'budgetEstimate' in sample) return 'projects';
  if ('ccEmails' in sample || 'currencyId' in sample || 'currencyCode' in sample) return 'clients';
  if ('workspaceId' in sample && 'name' in sample && 'id' in sample) return 'tags';
  return 'generic';
}

const records = collectRecords();
if (records.length === 0) return [];

const kind = detectKind(records[0]);
if (kind === 'users') return transformUsers(records);
if (kind === 'projects') return transformProjects(records);
if (kind === 'clients') return transformClients(records);
if (kind === 'tags') return transformTags(records);

return withPair(records.map(item => {
  if (item && typeof item === 'object') {
    return { json: { ...item, id: String(item.id || '') } };
  }
  return { json: { id: String(item || ''), value: item } };
}));

// Extrai o array 'data' da resposta da API VHSYS
// Combina dados de todas as páginas e transforma em itens individuais

const items = $input.all();
const pairedItem = $input.first().pairedItem ?? { item: 0 };

let dataArray = [];

// Coleta dados de todas as páginas
for (const inputItem of items) {
  const data = inputItem.json?.data;
  if (Array.isArray(data)) {
    dataArray = dataArray.concat(data);
  }
}

// Verifica se existe o campo 'data'
if (dataArray.length === 0) {
  return [];
}

console.log(`VHSYS: Processando ${dataArray.length} registros de ${items.length} páginas`);

// Transforma cada elemento do array em um item separado
return dataArray.map(item => ({
  json: item,
  pairedItem
}));

