{{ (() => {
const data = $json;

const table = $("Split Out").item.json.table;
const idField = $("Split Out").item.json.id_field;
const schema = "raw_data";

const fields = Object.keys(data).filter(
  (key) =>
    !key.startsWith("_") &&
    !key.startsWith("$") &&
    key !== "json" &&
    key !== "pairedItem",
);

if (fields.length === 0) {
  return 'SELECT 1'
}

const normalizedIdField = idField.toLowerCase();
const columns = fields.map((f) => '"' + f.toLowerCase() + '"').join(", ");
const values = fields.map((f) => escapeSqlValue(data[f])).join(", ");
const updateSet = fields
  .filter((f) => f.toLowerCase() !== normalizedIdField)
  .map((f) => '"' + f.toLowerCase() + '" = EXCLUDED."' + f.toLowerCase() + '"')
  .join(", ");

return (
  "INSERT INTO " +
  schema +
  "." +
  table +
  " (" +
  columns +
  ") VALUES (" +
  values +
  ') ON CONFLICT ("' +
  normalizedIdField +
  '") DO UPDATE SET ' +
  updateSet +
  ";"
);

function escapeSqlValue(value) {
  if (value === null || value === undefined || value === "") {
    return "NULL";
  }
  if (typeof value === "string" && value.startsWith("0000-00-00")) {
    return "NULL";
  }
  if (typeof value === "number") {
    return value;
  }
  if (typeof value === "boolean") {
    return value ? "true" : "false";
  }
  if (Array.isArray(value) || typeof value === "object") {
    return "'" + JSON.stringify(value).replace(/'/g, "''") + "'::jsonb";
  }
  return "'" + String(value).replace(/'/g, "''") + "'";
}
})() }}

