return items.map(item => {
    if (table === 'vhs_ordens_servico') {
        item.json.ref_centros_custo = extractCostCenterByCC([item.json.obs_interno_pedido, item.json.referencia_ordem]);
    }
    else if (table === 'vhs_pedidos') {
        item.json.ref_centros_custo = extractCostCenterByCC([item.json.referencia_pedido, item.json.obs_pedido]);
    }
    else if (table === 'vhs_notas_fiscais') {
        item.json.ref_centros_custo = extractCostCenterByCC([item.json.referencia_pedido, item.json.obs_interno_pedido]);
    }
    else if (table === 'vhs_centro_custos') {
        item.json.ref_centros_custo = extractCostCenter(item.json.desc_centro_custos);
    }
    else if (table === 'clk_projetos') {
        item.json.ref_centros_custo = extractCostCenter(item.json.name);
          item.json.duration_minutes = convertTimeToMinutes(item.json.duration);
    }
    return item;
});

function extractCostCenterByCC(list) {
    let ref = null;

    for (const key in list) {
        if (list[key] && typeof list[key] === 'string') {
                let match = list[key].match(/CC[-\s]?(\d{1,10})/i);
                if (match && match[1]) {
                      ref = match[1];
                    break;
                }
                if (!ref) {
                    match = list[key].match(/\b(\d{6})\b/);
                    if (match && match[1]) {
                        ref = match[1];
                        break;
                    }
                }
        }
    }
    return ref ? String(ref) : null;
}

function extractCostCenter(text) {
    if (text === 'Vendas' || text === 'Administração') {
        return text;
    }
    let ref = null;
    const match6 = text && text.match(/\b(\d{6})\b/);
    if (match6) ref = match6[1];
    if (!ref) {
        const matchPrefix = text && text.match(/^[A-Z]{2}-[A-Z0-9]{3}/);
        if (matchPrefix) ref = matchPrefix[0];
    }
    if (!ref) {
        const matchCC = text && text.match(/CC[-\s]*(\d+)/i);
        if (matchCC) ref = matchCC[1];
    }
    if (!ref) {
        const index = text && text.indexOf('CC-');
        if (index !== -1) ref = text.substr(index + 3, 6);
    }
    if (!ref) {
        let desc = text ? text.replace('/', '') : '';
        const index = desc.indexOf('CC-');
        if (index !== -1) {
            const endIndex = desc.indexOf('/', index);
            if (endIndex === -1) {
                ref = desc.substr(index + 3, 6);
            } else {
                ref = desc.substring(index + 3, endIndex);
            }
        }
    }
    return ref ? String(ref) : null;
};


function convertTimeToMinutes(timeString) {
  // Example: "PT47H30M"
  const match = timeString && timeString.match(/^PT(\d+)H(?:(\d+)M)?(?:(\d+)S)?$/);
  if (match) {
    const hours = parseInt(match[1], 10);
    const minutes = match[2] ? parseInt(match[2], 10) : 0;
    const seconds = match[3] ? parseInt(match[3], 10) : 0;
    return hours * 60 + minutes + seconds / 60;
  }
  return 0;
};
